/**
 * Formats date to predefined formats
 * @param {Date | String} date Date to be formatted
 * @param {FormatType | String} outputFormat Expected format
 * @return {String} date formatted
 */
export const formatDate = (
  date: Date | string,
  outputFormat: FormatType | string,
  fallback?: string,
  timeZone?: string
): string => {
  if (!date) {
    return fallback || 'N/A';
  }

  try {
    const dateObj = getDateObj(date);

    switch (outputFormat) {
      case 'ShortDate':
        return format(dateObj, 'P');
      case 'DateSerialized':
        return format(dateObj, 'yyyy-MM-dd');
      case 'Time':
        return format(dateObj, 'p');
      case 'DaysAgo':
        return formatDistanceToNowStrict(dateObj, { addSuffix: true, unit: 'day' });
      case 'TimeAgo':
        return formatDistanceToNow(dateObj, { addSuffix: true });
      case 'DateTimeSecondsTZ':
        // note that we're getting locale as en-US via default date-fns behavior
